def modp(n: int, p: int):
    """
    Return 2^n modulo p (be aware of numerics).
    """
    def pow_mod(base: int, exponent: int, modulus: int) -> int:
        result = 1
        while exponent > 0:
            if exponent % 2 == 1:
                result = (result * base) % modulus
            exponent //= 2
            base = (base * base) % modulus
        return result

    return pow_mod(2, n, p)
```

